/**
 * StatsMonitor - Simple FPS/MS/Memory monitor using stats.js
 *
 * This is a reliable fallback for r3f-perf when it has compatibility issues.
 *
 * Usage:
 * - Shows real-time FPS, frame time (MS), and memory usage (MB)
 * - Toggle panels by clicking on the stats panel
 * - Press 'S' key to toggle visibility
 *
 * Integration:
 * - Import and add <StatsMonitor /> inside your component (NOT inside Canvas)
 * - For R3F: Use the StatsR3F component inside the Canvas
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { useFrame } from '@react-three/fiber';
import Stats from 'stats.js';

// ─────────────────────────────────────────────────────────────
// STATS MONITOR (for use outside Canvas)
// ─────────────────────────────────────────────────────────────

interface StatsMonitorProps {
  /** Whether the stats panel is visible */
  visible?: boolean;
  /** Position of the panel */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
}

/**
 * Stats monitor component using stats.js
 * Render this OUTSIDE the R3F Canvas
 */
export function StatsMonitor({ visible = true, position = 'top-left' }: StatsMonitorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const statsRef = useRef<Stats | null>(null);
  const frameIdRef = useRef<number>(0);

  useEffect(() => {
    if (!visible || !containerRef.current) return;

    // Create stats instance
    const stats = new Stats();
    stats.showPanel(0); // 0: fps, 1: ms, 2: mb
    statsRef.current = stats;

    // Style the container
    const dom = stats.dom;
    dom.style.position = 'relative';
    dom.style.top = '0';
    dom.style.left = '0';

    containerRef.current.appendChild(dom);

    // Animation loop for stats update
    let lastTime = performance.now();
    const animate = () => {
      const currentTime = performance.now();
      // Only update stats if enough time has passed (throttle to ~60fps)
      if (currentTime - lastTime >= 16) {
        stats.update();
        lastTime = currentTime;
      }
      frameIdRef.current = requestAnimationFrame(animate);
    };
    frameIdRef.current = requestAnimationFrame(animate);

    return () => {
      if (frameIdRef.current) {
        cancelAnimationFrame(frameIdRef.current);
      }
      if (containerRef.current && dom.parentNode === containerRef.current) {
        containerRef.current.removeChild(dom);
      }
      statsRef.current = null;
    };
  }, [visible]);

  if (!visible) return null;

/**
 * MMS Data Types
 *
 * Architecture: Persistence vs Rendering
 *
 * Data flows through two distinct layers:
 *
 * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
 *   startDate: string      (Date objects)       startDay: 74
 *   "2024-03-15"           for logic            trainIndex: 5
 *
 * Why this separation?
 * - Date objects cannot be serialized to JSON (become {})
 * - Canvas needs numeric offsets for position calculations
 * - Domain logic needs semantic dates for business rules
 */

import { extent, max } from 'd3-array';

// ─────────────────────────────────────────────────────────────
// ENUMS & CONSTANTS
// ─────────────────────────────────────────────────────────────

export type AssetType = 'ALSTOM' | 'KINKI';
export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';

// ─────────────────────────────────────────────────────────────
// DOMAIN TYPES (Persistent/Serializable)
// These types can be saved to JSON, sent via API, or stored in localStorage.
// ─────────────────────────────────────────────────────────────

export interface Train {
  id: string;              // "TRAIN-001" or "ALT-001"
  name: string;            // Display name
  assetType: AssetType;    // Fleet type
}

export interface Task {
  id: string;              // Unique identifier
  trainId: string;         // Reference to Train.id
  startDate: string;       // ISO 8601 date: "2024-03-15"
  endDate: string;         // ISO 8601 date: "2024-03-20"
  type: TaskType;          // Visual category
  hasConflict: boolean;    // Conflict indicator
  predecessorId?: string;  // Optional: ID of task that must complete before this one (F023)
}

export interface DatasetMeta {
  startDate: string;       // ISO 8601: "2024-01-01"
  trainCount: number;      // Number of trains
  years: number;           // Time range in years
}

export interface GeneratedData {
  trains: Train[];
  tasks: Task[];
  meta: DatasetMeta;
}

// ─────────────────────────────────────────────────────────────
// RENDERING TYPES (Runtime/Calculated)
// These types are computed when data loads and used by the canvas.
// Never persisted.
// ─────────────────────────────────────────────────────────────

export type TaskColor = 'blue' | 'orange' | 'gray';

export interface TaskRender {
  id: string;              // Same as Task.id
  trainIndex: number;      // Y position (0-based index in trains array)
  startDay: number;        // X position (days since meta.startDate)
  duration: number;        // Width (days)
  color: TaskColor;        // Derived from Task.type
  hasConflict: boolean;    // Passthrough from Task
  type: TaskType;          // For label display in MicroLayer
  predecessorId?: string;  // Optional: ID of predecessor task (F023)
}

export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
  maintenance: 'blue',
  overhaul: 'orange',
  inspection: 'gray',
};

// ─────────────────────────────────────────────────────────────
// WORLD BOUNDS (Navigation limits)
// ─────────────────────────────────────────────────────────────

/**
 * Defines the navigable world boundaries.
 * Camera will be clamped to these bounds.
 *
 * Coordinate system:
 * - X: 0 = first day, positive = future
 * - Y: 0 = top (TRAIN-001), negative = down (more trains)
 */
export interface WorldBounds {
  minX: number;  // 0 (first day)
  maxX: number;  // totalDays * pxPerDay

/**
 * MacroLayer - Strategic heatmap visualization
 *
 * Renders a heatmap showing task density across trains and time.
 * Visible at zoom levels < 0.5x (MACRO LOD level).
 *
 * Features:
 * - Aggregates tasks by month/train into cells
 * - Color gradient: yellow (low) → orange (medium) → red (high density)
 * - InstancedMesh for optimal performance
 * - Shows 10-20 year strategic overview
 *
 * D3-MIGRATE-001: Uses d3-scale-chromatic for heatmap color interpolation
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';
import { interpolateYlOrRd } from 'd3-scale-chromatic';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

interface MacroLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  totalYears?: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
}

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Heatmap cell size
const DAYS_PER_CELL = 30; // ~1 month per cell
const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px per train row
const CELL_GAP = 1; // Small gap between cells

// Empty cell background color
const EMPTY_CELL_COLOR = '#f8fafc'; // slate-50

/**
 * Interpolate between colors based on density (0-1)
 * D3-MIGRATE-001: Uses d3-scale-chromatic interpolateYlOrRd for heatmap colors
 *
 * The YlOrRd (Yellow-Orange-Red) scale is a standard sequential color scheme
 * designed for heatmaps, providing perceptually uniform color progression.
 */
function getHeatmapColor(density: number): Color {
  // No tasks = light background
  if (density === 0) {
    return new Color(EMPTY_CELL_COLOR);
  }

  // Normalize density (0-1 range, with max around 8 tasks)
  const normalizedDensity = Math.min(density / 8, 1);

  // Use d3 YlOrRd scale (0 = yellow, 1 = red)
  // Start at 0.1 to avoid very light yellow for low values
  const t = 0.1 + normalizedDensity * 0.9;
  const colorString = interpolateYlOrRd(t);

  return new Color(colorString);
}

/**
 * Calculate task density per cell
 * Returns a 2D array: [trainIndex][monthIndex] = task count
 */
function calculateDensityGrid(
  tasks: TaskRender[],
  trainCount: number,
  totalMonths: number
): number[][] {
  // Initialize grid with zeros
  const grid: number[][] = Array.from({ length: trainCount }, () =>
    Array(totalMonths).fill(0)
  );

