/**
 * EntityStore - STATE-ARCH-001 Phase 1
 *
 * High-performance TypedArray-based entity storage using Structure of Arrays (SoA).
 * Optimized for WebGL rendering with zero GC pressure in hot path.
 *
 * Key features:
 * - TypedArrays for numeric data (cache-friendly iteration)
 * - Bulk loading optimized for initial data
 * - Cursor-based access (zero-allocation reads)
 * - Direct mutation (no Proxy overhead)
 *
 * Performance targets:
 * - 100k entities in ~1.7MB
 * - Zero GC during pan/zoom
 * - <1ms for bulk load of 5k entities
 */

import { DEFAULT_VIEW_CONFIG } from '../data/types';
import type {
  IEntityStore,
  TaskArrays,
  TaskStringData,
  TaskData,
  TaskCursor,
  TaskTypeValue,
  TaskColorValue,
} from './types';
import {
  TASK_TYPE_TO_VALUE,
  VALUE_TO_TASK_TYPE,
  TASK_COLOR_TO_VALUE,
  VALUE_TO_TASK_COLOR,
} from './types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

/**
 * Default initial capacity (will grow if needed)
 */
const DEFAULT_CAPACITY = 10000;

/**
 * Growth factor when arrays need to be resized
 */
const GROWTH_FACTOR = 1.5;

/**
 * Create TaskArrays with given capacity
 */
function createArrays(capacity: number): TaskArrays {
  return {
    startDay: new Float32Array(capacity),
    duration: new Float32Array(capacity),
    trainIndex: new Uint16Array(capacity),
    type: new Uint8Array(capacity),
    color: new Uint8Array(capacity),
    hasConflict: new Uint8Array(capacity),
    predecessorIndex: new Int32Array(capacity).fill(-1),
  };
}

/**
 * Resize arrays to new capacity, preserving existing data
 */
function resizeArrays(
  oldArrays: TaskArrays,
  oldCount: number,
  newCapacity: number
): TaskArrays {
  const newArrays = createArrays(newCapacity);

  // Copy existing data
  newArrays.startDay.set(oldArrays.startDay.subarray(0, oldCount));
  newArrays.duration.set(oldArrays.duration.subarray(0, oldCount));
  newArrays.trainIndex.set(oldArrays.trainIndex.subarray(0, oldCount));
  newArrays.type.set(oldArrays.type.subarray(0, oldCount));
  newArrays.color.set(oldArrays.color.subarray(0, oldCount));
  newArrays.hasConflict.set(oldArrays.hasConflict.subarray(0, oldCount));
  newArrays.predecessorIndex.set(oldArrays.predecessorIndex.subarray(0, oldCount));

  return newArrays;
}

/**
 * TaskCursor implementation - lightweight view into arrays
 */
class TaskCursorImpl implements TaskCursor {
  constructor(
    private readonly store: EntityStore,
    public readonly index: number
  ) {}

  get id(): string {
    return this.store.strings.ids.get(this.index) ?? '';
  }

  get startDay(): number {
    return this.store.arrays.startDay[this.index];
  }

